PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:5', 31, 5, 21, 411, 3474, 'اُولٰۤىِٕكَ عَلٰى هُدًى مِّنْ رَّبِّهِمْ وَاُولٰۤىِٕكَ هُمُ الْمُفْلِحُوْنَ', 'Merekalah yang mendapat petunjuk dari Tuhannya dan mereka itulah orang-orang yang beruntung.', '', 'https://everyayah.com/data/Alafasy_128kbps/031005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:6', 31, 6, 21, 411, 3475, 'وَمِنَ النَّاسِ مَنْ يَّشْتَرِيْ لَهْوَ الْحَدِيْثِ لِيُضِلَّ عَنْ سَبِيْلِ اللّٰهِ بِغَيْرِ عِلْمٍۖ وَّيَتَّخِذَهَا هُزُوًاۗ اُولٰۤىِٕكَ لَهُمْ عَذَابٌ مُّهِيْنٌ', 'Di antara manusia ada orang yang membeli percakapan kosong untuk menyesatkan (manusia) dari jalan Allah tanpa ilmu dan menjadikannya olok-olokan. Mereka itu akan memperoleh azab yang menghinakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/031006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:7', 31, 7, 21, 411, 3476, 'وَاِذَا تُتْلٰى عَلَيْهِ اٰيٰتُنَا وَلّٰى مُسْتَكْبِرًا كَاَنْ لَّمْ يَسْمَعْهَا كَاَنَّ فِيْٓ اُذُنَيْهِ وَقْرًاۚ فَبَشِّرْهُ بِعَذَابٍ اَلِيْمٍ', 'Apabila dibacakan kepadanya597) ayat-ayat Kami, dia berpaling dengan menyombongkan diri seolah-olah dia tidak mendengarnya, seakan-akan ada sumbatan di kedua telinganya. Maka, berilah kabar gembira kepadanya dengan azab yang pedih.', '597) Pesan dari ayat ini ditujukan kepada orang yang mempergunakan percakapan kosong (segala hal yang memalingkan hati dari ketaatan kepada Allah Swt.) untuk menyesatkan manusia.', 'https://everyayah.com/data/Alafasy_128kbps/031007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:8', 31, 8, 21, 411, 3477, 'اِنَّ الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ لَهُمْ جَنّٰتُ النَّعِيْمِۙ', 'Sesungguhnya orang-orang yang beriman dan mengerjakan kebajikan, baginya surga-surga yang penuh kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/031008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:9', 31, 9, 21, 411, 3478, 'خٰلِدِيْنَ فِيْهَاۗ وَعْدَ اللّٰهِ حَقًّاۗ وَهُوَ الْعَزِيْزُ الْحَكِيْمُ', 'Mereka kekal di dalamnya sebagai janji Allah yang benar. Dia Maha Perkasa lagi Maha Bijaksana.', '', 'https://everyayah.com/data/Alafasy_128kbps/031009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:10', 31, 10, 21, 411, 3479, 'خَلَقَ السَّمٰوٰتِ بِغَيْرِ عَمَدٍ تَرَوْنَهَا وَاَلْقٰى فِى الْاَرْضِ رَوَاسِيَ اَنْ تَمِيْدَ بِكُمْ وَبَثَّ فِيْهَا مِنْ كُلِّ دَاۤبَّةٍۗ وَاَنْزَلْنَا مِنَ السَّمَاۤءِ مَاۤءً فَاَنْۢبَتْنَا فِيْهَا مِنْ كُلِّ زَوْجٍ كَرِيْمٍ ', 'Dia menciptakan langit tanpa tiang (seperti) yang kamu lihat dan meletakkan di bumi gunung-gunung (yang kukuh) agar ia tidak mengguncangkanmu serta menyebarkan padanya (bumi) segala jenis makhluk bergerak. Kami (juga) menurunkan air hujan dari langit,  lalu Kami menumbuhkan padanya segala pasangan yang baik.', '', 'https://everyayah.com/data/Alafasy_128kbps/031010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:11', 31, 11, 21, 411, 3480, 'هٰذَا خَلْقُ اللّٰهِ فَاَرُوْنِيْ مَاذَا خَلَقَ الَّذِيْنَ مِنْ دُوْنِهٖۗ بَلِ الظّٰلِمُوْنَ فِيْ ضَلٰلٍ مُّبِيْنٍ ࣖ', 'Inilah ciptaan Allah. Maka, perlihatkanlah kepadaku apa yang telah diciptakan oleh (sembahanmu) selain-Nya. Sebenarnya orang-orang zalim itu berada di dalam kesesatan yang nyata.', '', 'https://everyayah.com/data/Alafasy_128kbps/031011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:12', 31, 12, 21, 412, 3481, 'وَلَقَدْ اٰتَيْنَا لُقْمٰنَ الْحِكْمَةَ اَنِ اشْكُرْ لِلّٰهِ ۗوَمَنْ يَّشْكُرْ فَاِنَّمَا يَشْكُرُ لِنَفْسِهٖۚ وَمَنْ كَفَرَ فَاِنَّ اللّٰهَ غَنِيٌّ حَمِيْدٌ ', 'Sungguh, Kami benar-benar telah memberikan hikmah kepada Luqman, yaitu, “Bersyukurlah kepada Allah! Siapa yang bersyukur, sesungguhnya dia bersyukur untuk dirinya sendiri. Siapa yang kufur (tidak bersyukur), sesungguhnya Allah Maha Kaya lagi Maha Terpuji.”', '', 'https://everyayah.com/data/Alafasy_128kbps/031012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:13', 31, 13, 21, 412, 3482, 'وَاِذْ قَالَ لُقْمٰنُ لِابْنِهٖ وَهُوَ يَعِظُهٗ يٰبُنَيَّ لَا تُشْرِكْ بِاللّٰهِ ۗاِنَّ الشِّرْكَ لَظُلْمٌ عَظِيْمٌ ', '(Ingatlah) ketika Luqman berkata kepada anaknya, saat dia menasihatinya, “Wahai anakku, janganlah mempersekutukan Allah! Sesungguhnya mempersekutukan (Allah) itu benar-benar kezaliman yang besar.”', '', 'https://everyayah.com/data/Alafasy_128kbps/031013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:14', 31, 14, 21, 412, 3483, 'وَوَصَّيْنَا الْاِنْسَانَ بِوَالِدَيْهِۚ حَمَلَتْهُ اُمُّهٗ وَهْنًا عَلٰى وَهْنٍ وَّفِصَالُهٗ فِيْ عَامَيْنِ اَنِ اشْكُرْ لِيْ وَلِوَالِدَيْكَۗ اِلَيَّ الْمَصِيْرُ', 'Kami mewasiatkan kepada manusia (agar berbuat baik) kepada kedua orang tuanya. Ibunya telah mengandungnya dalam keadaan lemah yang bertambah-tambah dan menyapihnya dalam dua tahun.598) (Wasiat Kami,) “Bersyukurlah kepada-Ku dan kepada kedua orang tuamu.” Hanya kepada-Ku (kamu) kembali.', '598) Selambat-lambat waktu menyapih ialah sampai anak berumur 2 tahun.', 'https://everyayah.com/data/Alafasy_128kbps/031014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:15', 31, 15, 21, 412, 3484, 'وَاِنْ جَاهَدٰكَ عَلٰٓى اَنْ تُشْرِكَ بِيْ مَا لَيْسَ لَكَ بِهٖ عِلْمٌ فَلَا تُطِعْهُمَا وَصَاحِبْهُمَا فِى الدُّنْيَا مَعْرُوْفًا ۖوَّاتَّبِعْ سَبِيْلَ مَنْ اَنَابَ اِلَيَّۚ  ثُمَّ اِلَيَّ مَرْجِعُكُمْ فَاُنَبِّئُكُمْ بِمَا كُنْتُمْ تَعْمَلُوْنَ', 'Jika keduanya memaksamu untuk mempersekutukan-Ku dengan sesuatu yang engkau tidak punya ilmu tentang itu, janganlah patuhi keduanya, (tetapi) pergaulilah keduanya di dunia dengan baik dan ikutilah jalan orang yang kembali kepada-Ku. Kemudian, hanya kepada-Ku kamu kembali, lalu Aku beri tahukan kepadamu apa yang biasa kamu kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/031015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:16', 31, 16, 21, 412, 3485, 'يٰبُنَيَّ اِنَّهَآ اِنْ تَكُ مِثْقَالَ حَبَّةٍ مِّنْ خَرْدَلٍ فَتَكُنْ فِيْ صَخْرَةٍ اَوْ فِى السَّمٰوٰتِ اَوْ فِى الْاَرْضِ يَأْتِ بِهَا اللّٰهُ ۗاِنَّ اللّٰهَ لَطِيْفٌ خَبِيْرٌ', '(Luqman berkata,) “Wahai anakku, sesungguhnya jika ada (suatu perbuatan) seberat biji sawi dan berada dalam batu, di langit, atau di bumi, niscaya Allah akan menghadirkannya (untuk diberi balasan). Sesungguhnya Allah Maha Lembut599) lagi Maha Teliti.', '599) Allah Maha Lembut artinya ialah ilmu Allah itu meliputi segala sesuatu, betapapun kecilnya.', 'https://everyayah.com/data/Alafasy_128kbps/031016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:17', 31, 17, 21, 412, 3486, 'يٰبُنَيَّ اَقِمِ الصَّلٰوةَ وَأْمُرْ بِالْمَعْرُوْفِ وَانْهَ عَنِ الْمُنْكَرِ وَاصْبِرْ عَلٰى مَآ اَصَابَكَۗ اِنَّ ذٰلِكَ مِنْ عَزْمِ الْاُمُوْرِ', 'Wahai anakku, tegakkanlah salat dan suruhlah (manusia) berbuat yang makruf dan cegahlah (mereka) dari yang mungkar serta bersabarlah terhadap apa yang menimpamu. Sesungguhnya yang demikian itu termasuk urusan yang (harus) diutamakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/031017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:18', 31, 18, 21, 412, 3487, 'وَلَا تُصَعِّرْ خَدَّكَ لِلنَّاسِ وَلَا تَمْشِ فِى الْاَرْضِ مَرَحًاۗ اِنَّ اللّٰهَ لَا يُحِبُّ كُلَّ مُخْتَالٍ فَخُوْرٍۚ', 'Janganlah memalingkan wajahmu dari manusia (karena sombong) dan janganlah berjalan di bumi ini dengan angkuh. Sesungguhnya Allah tidak menyukai setiap orang yang sombong lagi sangat membanggakan diri.', '', 'https://everyayah.com/data/Alafasy_128kbps/031018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:19', 31, 19, 21, 412, 3488, 'وَاقْصِدْ فِيْ مَشْيِكَ وَاغْضُضْ مِنْ صَوْتِكَۗ اِنَّ اَنْكَرَ الْاَصْوَاتِ لَصَوْتُ الْحَمِيْرِ ࣖ', 'Berlakulah wajar dalam berjalan600) dan lembutkanlah suaramu. Sesungguhnya seburuk-buruk suara ialah suara keledai.”', '600) Ketika berjalan, janganlah terlampau cepat dan jangan pula terlalu lambat.', 'https://everyayah.com/data/Alafasy_128kbps/031019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:20', 31, 20, 21, 413, 3489, 'اَلَمْ تَرَوْا اَنَّ اللّٰهَ سَخَّرَ لَكُمْ مَّا فِى السَّمٰوٰتِ وَمَا فِى الْاَرْضِ وَاَسْبَغَ عَلَيْكُمْ نِعَمَهٗ ظَاهِرَةً وَّبَاطِنَةً ۗوَمِنَ النَّاسِ مَنْ يُّجَادِلُ فِى اللّٰهِ بِغَيْرِ عِلْمٍ وَّلَا هُدًى وَّلَا كِتٰبٍ مُّنِيْرٍ', 'Tidakkah kamu memperhatikan bahwa sesungguhnya Allah telah menundukkan apa yang ada di langit dan apa yang ada di bumi untukmu. Dia (juga) menyempurnakan nikmat-nikmat-Nya yang lahir dan batin untukmu. Akan tetapi, di antara manusia ada yang membantah (keesaan) Allah tanpa (berdasarkan) ilmu, petunjuk, dan kitab suci yang menerangi.', '', 'https://everyayah.com/data/Alafasy_128kbps/031020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:21', 31, 21, 21, 413, 3490, 'وَاِذَا قِيْلَ لَهُمُ اتَّبِعُوْا مَآ اَنْزَلَ اللّٰهُ قَالُوْا بَلْ نَتَّبِعُ مَا وَجَدْنَا عَلَيْهِ اٰبَاۤءَنَاۗ اَوَلَوْ كَانَ الشَّيْطٰنُ يَدْعُوْهُمْ اِلٰى عَذَابِ السَّعِيْرِ', 'Apabila dikatakan kepada mereka, “Ikutilah apa yang diturunkan Allah!” mereka menjawab, “(Tidak). Kami justru (hanya) mengikuti kebiasaan yang kami dapati dari nenek moyang kami.” Apakah (mereka akan mengikuti nenek moyang mereka,) walaupun sebenarnya setan menyeru mereka ke dalam azab api yang menyala-nyala (neraka)?', '', 'https://everyayah.com/data/Alafasy_128kbps/031021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:22', 31, 22, 21, 413, 3491, '۞ وَمَنْ يُّسْلِمْ وَجْهَهٗٓ اِلَى اللّٰهِ وَهُوَ مُحْسِنٌ فَقَدِ اسْتَمْسَكَ بِالْعُرْوَةِ الْوُثْقٰىۗ وَاِلَى اللّٰهِ عَاقِبَةُ الْاُمُوْرِ', 'Siapa yang berserah diri kepada Allah dan dia seorang muhsin, maka sungguh dia telah berpegang teguh pada buhul (tali) yang kukuh. Hanya kepada Allah kesudahan segala urusan.', '', 'https://everyayah.com/data/Alafasy_128kbps/031022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:23', 31, 23, 21, 413, 3492, 'وَمَنْ كَفَرَ فَلَا يَحْزُنْكَ كُفْرُهٗۗ اِلَيْنَا مَرْجِعُهُمْ فَنُنَبِّئُهُمْ بِمَا عَمِلُوْاۗ اِنَّ اللّٰهَ عَلِيْمٌۢ بِذَاتِ الصُّدُوْرِ', 'Siapa yang kufur, maka janganlah kekufurannya itu membuatmu (Nabi Muhammad) sedih. Kepada Kamilah tempat kembali mereka, lalu Kami memberitakan kepadanya apa yang telah mereka kerjakan. Sesungguhnya Allah Maha Mengetahui segala isi hati.', '', 'https://everyayah.com/data/Alafasy_128kbps/031023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:24', 31, 24, 21, 413, 3493, 'نُمَتِّعُهُمْ قَلِيْلًا ثُمَّ نَضْطَرُّهُمْ اِلٰى عَذَابٍ غَلِيْظٍ', 'Kami membiarkan mereka bersenang-senang sebentar, kemudian Kami memaksa mereka (masuk) ke dalam azab yang keras.', '', 'https://everyayah.com/data/Alafasy_128kbps/031024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:25', 31, 25, 21, 413, 3494, 'وَلَىِٕنْ سَاَلْتَهُمْ مَّنْ خَلَقَ السَّمٰوٰتِ وَالْاَرْضَ لَيَقُوْلُنَّ اللّٰهُ ۗقُلِ الْحَمْدُ لِلّٰهِ ۗبَلْ اَكْثَرُهُمْ لَا يَعْلَمُوْنَ', 'Sungguh, jika engkau (Nabi Muhammad) bertanya kepada mereka, “Siapakah yang menciptakan langit dan bumi?” pasti mereka akan menjawab, “Allah.” Katakanlah, “Segala puji bagi Allah,” tetapi kebanyakan mereka tidak mengetahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/031025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:26', 31, 26, 21, 413, 3495, 'لِلّٰهِ مَا فِى السَّمٰوٰتِ وَالْاَرْضِۗ اِنَّ اللّٰهَ هُوَ الْغَنِيُّ الْحَمِيْدُ', 'Milik Allahlah apa yang di langit dan di bumi. Sesungguhnya Allahlah Yang Maha Kaya lagi Maha Terpuji.', '', 'https://everyayah.com/data/Alafasy_128kbps/031026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:27', 31, 27, 21, 413, 3496, 'وَلَوْ اَنَّ مَا فِى الْاَرْضِ مِنْ شَجَرَةٍ اَقْلَامٌ وَّالْبَحْرُ يَمُدُّهٗ مِنْۢ بَعْدِهٖ سَبْعَةُ اَبْحُرٍ مَّا نَفِدَتْ كَلِمٰتُ اللّٰهِ ۗاِنَّ اللّٰهَ عَزِيْزٌ حَكِيْمٌ', 'Seandainya pohon-pohon di bumi menjadi pena dan lautan (menjadi tinta) ditambah tujuh lautan lagi setelah (kering)-nya, niscaya tidak akan pernah habis kalimatullah601) (ditulis dengannya). Sesungguhnya Allah Maha Perkasa lagi Maha Bijaksana.', '601) Yang dimaksud dengan kalimatullah pada ayat ini adalah ilmu dan hikmah-Nya.', 'https://everyayah.com/data/Alafasy_128kbps/031027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:28', 31, 28, 21, 413, 3497, 'مَا خَلْقُكُمْ وَلَا بَعْثُكُمْ اِلَّا كَنَفْسٍ وَّاحِدَةٍ ۗاِنَّ اللّٰهَ سَمِيْعٌۢ بَصِيْرٌ', 'Menciptakan dan membangkitkan kamu (bagi Allah) hanyalah seperti (mudahnya menciptakan dan membangkitkan) satu jiwa saja. Sesungguhnya Allah Maha Mendengar lagi Maha Melihat.', '', 'https://everyayah.com/data/Alafasy_128kbps/031028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:29', 31, 29, 21, 414, 3498, 'اَلَمْ تَرَ اَنَّ اللّٰهَ يُوْلِجُ الَّيْلَ فِى النَّهَارِ وَيُوْلِجُ النَّهَارَ فِى الَّيْلِ وَسَخَّرَ الشَّمْسَ وَالْقَمَرَۖ  كُلٌّ يَّجْرِيْٓ اِلٰٓى اَجَلٍ مُّسَمًّى وَّاَنَّ اللّٰهَ بِمَا تَعْمَلُوْنَ خَبِيْرٌ', 'Tidakkah engkau memperhatikan bahwa sesungguhnya Allah memasukkan malam ke dalam siang, memasukkan siang ke dalam malam, dan menundukkan matahari dan bulan, masing-masing beredar sampai pada waktu yang ditentukan? (Tidakkah pula engkau memperhatikan bahwa) sesungguhnya Allah Maha Teliti terhadap apa yang kamu kerjakan?', '', 'https://everyayah.com/data/Alafasy_128kbps/031029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:30', 31, 30, 21, 414, 3499, 'ذٰلِكَ بِاَنَّ اللّٰهَ هُوَ الْحَقُّ وَاَنَّ مَا يَدْعُوْنَ مِنْ دُوْنِهِ الْبَاطِلُۙ وَاَنَّ اللّٰهَ هُوَ الْعَلِيُّ الْكَبِيْرُ ࣖ', 'Demikian itu karena sesungguhnya Allahlah (Tuhan) yang sebenar-benarnya, apa saja yang mereka seru selain Allah adalah batil, dan sesungguhnya Allahlah Yang Maha Tinggi lagi Maha Besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/031030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:31', 31, 31, 21, 414, 3500, 'اَلَمْ تَرَ اَنَّ الْفُلْكَ تَجْرِيْ فِى الْبَحْرِ بِنِعْمَتِ اللّٰهِ لِيُرِيَكُمْ مِّنْ اٰيٰتِهٖۗ اِنَّ فِيْ ذٰلِكَ لَاٰيٰتٍ لِّكُلِّ صَبَّارٍ شَكُوْرٍ', 'Tidakkah engkau memperhatikan bahwa sesungguhnya kapal itu berlayar di laut berkat nikmat Allah agar Dia memperlihatkan kepadamu sebagian dari tanda-tanda (kebesaran)-Nya. Sesungguhnya pada yang demikian itu terdapat tanda-tanda bagi setiap orang yang sangat sabar dan banyak bersyukur.', '', 'https://everyayah.com/data/Alafasy_128kbps/031031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:32', 31, 32, 21, 414, 3501, 'وَاِذَا غَشِيَهُمْ مَّوْجٌ كَالظُّلَلِ دَعَوُا اللّٰهَ مُخْلِصِيْنَ لَهُ الدِّيْنَ ەۚ فَلَمَّا نَجّٰىهُمْ اِلَى الْبَرِّ فَمِنْهُمْ مُّقْتَصِدٌۗ وَمَا يَجْحَدُ بِاٰيٰتِنَآ اِلَّا كُلُّ خَتَّارٍ كَفُوْرٍ', 'Apabila mereka digulung ombak besar seperti awan tebal, mereka menyeru kepada Allah dengan memurnikan ketaatan hanya bagi-Nya. Kemudian, ketika Allah menyelamatkan mereka sampai di daratan, sebagian kecil (saja) di antara mereka yang tetap menempuh jalan yang lurus.602) Tidak ada yang mengingkari ayat-ayat Kami selain pengkhianat yang tidak berterima kasih.', '602) Yang dimaksud jalan yang lurus adalah mengakui keesaan Allah Swt.', 'https://everyayah.com/data/Alafasy_128kbps/031032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:33', 31, 33, 21, 414, 3502, 'يٰٓاَيُّهَا النَّاسُ اتَّقُوْا رَبَّكُمْ وَاخْشَوْا يَوْمًا لَّا يَجْزِيْ وَالِدٌ عَنْ وَّلَدِهٖۖ وَلَا مَوْلُوْدٌ هُوَ جَازٍ عَنْ وَّالِدِهٖ شَيْـًٔاۗ اِنَّ وَعْدَ اللّٰهِ حَقٌّ فَلَا تَغُرَّنَّكُمُ الْحَيٰوةُ الدُّنْيَاۗ وَلَا يَغُرَّنَّكُمْ بِاللّٰهِ الْغَرُوْرُ', 'Wahai manusia, bertakwalah kepada Tuhanmu dan takutlah akan hari yang (ketika itu) seorang bapak tidak dapat membela anaknya dan seorang anak tidak dapat (pula) membela bapaknya sedikit pun! Sesungguhnya janji Allah adalah benar, maka janganlah sekali-kali kamu diperdaya oleh kehidupan dunia dan jangan sampai karena (kebaikan-kebaikan) Allah kamu diperdaya oleh penipu.', '', 'https://everyayah.com/data/Alafasy_128kbps/031033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('31:34', 31, 34, 21, 414, 3503, 'اِنَّ اللّٰهَ عِنْدَهٗ عِلْمُ السَّاعَةِۚ وَيُنَزِّلُ الْغَيْثَۚ وَيَعْلَمُ مَا فِى الْاَرْحَامِۗ وَمَا تَدْرِيْ نَفْسٌ مَّاذَا تَكْسِبُ غَدًاۗ وَمَا تَدْرِيْ نَفْسٌۢ بِاَيِّ اَرْضٍ تَمُوْتُۗ اِنَّ اللّٰهَ عَلِيْمٌ خَبِيْرٌ ࣖ', 'Sesungguhnya Allah memiliki pengetahuan tentang hari Kiamat, menurunkan hujan, dan mengetahui apa yang ada dalam rahim. Tidak ada seorang pun yang dapat mengetahui (dengan pasti) apa yang akan dia kerjakan besok.603) (Begitu pula,) tidak ada seorang pun yang dapat mengetahui di bumi mana dia akan mati. Sesungguhnya Allah Maha Mengetahui lagi Maha Teliti.', '603) Manusia tidak dapat mengetahui dengan pasti apa yang akan dikerjakannya besok atau yang akan diperolehnya, namun mereka diwajibkan berusaha.', 'https://everyayah.com/data/Alafasy_128kbps/031034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:1', 32, 1, 21, 415, 3504, ' الۤمّۤ ۗ ', 'Alif Lām Mīm.', '', 'https://everyayah.com/data/Alafasy_128kbps/032001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:2', 32, 2, 21, 415, 3505, 'تَنْزِيْلُ الْكِتٰبِ لَا رَيْبَ فِيْهِ مِنْ رَّبِّ الْعٰلَمِيْنَۗ ', 'Turunnya Al-Qur’an yang tidak ada keraguan di dalamnya berasal dari Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/032002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:3', 32, 3, 21, 415, 3506, 'اَمْ يَقُوْلُوْنَ افْتَرٰىهُ ۚ بَلْ هُوَ الْحَقُّ مِنْ رَّبِّكَ لِتُنْذِرَ قَوْمًا مَّآ اَتٰىهُمْ مِّنْ نَّذِيْرٍ مِّنْ قَبْلِكَ لَعَلَّهُمْ يَهْتَدُوْنَ', 'Akan tetapi, mengapa mereka (orang kafir) mengatakan, “Dia (Nabi Muhammad) telah mengada-adakannya.” Sebaliknya, Al-Qur’an itulah kebenaran (yang datang) dari Tuhanmu agar engkau memberi peringatan kepada kaum yang sama sekali belum pernah didatangi seorang pemberi peringatan sebelum engkau. (Demikian ini) agar mereka mendapat petunjuk.', '', 'https://everyayah.com/data/Alafasy_128kbps/032003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:4', 32, 4, 21, 415, 3507, 'اَللّٰهُ الَّذِيْ خَلَقَ السَّمٰوٰتِ وَالْاَرْضَ وَمَا بَيْنَهُمَا فِيْ سِتَّةِ اَيَّامٍ ثُمَّ اسْتَوٰى عَلَى الْعَرْشِۗ مَا لَكُمْ مِّنْ دُوْنِهٖ مِنْ وَّلِيٍّ وَّلَا شَفِيْعٍۗ  اَفَلَا تَتَذَكَّرُوْنَ', 'Allah adalah Zat yang menciptakan langit dan bumi serta apa yang ada di antara keduanya dalam enam masa, kemudian Dia bersemayam di atas ‘Arasy.604) Bagimu tidak ada seorang pun pelindung dan pemberi syafaat selain Dia. Maka, apakah kamu tidak memperhatikan?', '604) Lihat catatan kaki surah al-A‘rāf (7): 54.', 'https://everyayah.com/data/Alafasy_128kbps/032004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:5', 32, 5, 21, 415, 3508, 'يُدَبِّرُ الْاَمْرَ مِنَ السَّمَاۤءِ اِلَى الْاَرْضِ ثُمَّ يَعْرُجُ اِلَيْهِ فِيْ يَوْمٍ كَانَ مِقْدَارُهٗٓ اَلْفَ سَنَةٍ مِّمَّا تَعُدُّوْنَ', 'Dia mengatur segala urusan dari langit ke bumi, kemudian (segala urusan) itu naik kepada-Nya605) pada hari yang kadarnya (lamanya) adalah seribu tahun menurut perhitunganmu.', '605) Yang dimaksud urusan itu naik kepada-Nya adalah beritanya dibawa oleh malaikat. Ayat ini merupakan tamsil bagi kebesaran Allah Swt. dan keagungan-Nya.', 'https://everyayah.com/data/Alafasy_128kbps/032005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:6', 32, 6, 21, 415, 3509, 'ذٰلِكَ عٰلِمُ الْغَيْبِ وَالشَّهَادَةِ الْعَزِيْزُ الرَّحِيْمُۙ ', 'Itu adalah (Tuhan) yang mengetahui yang gaib dan yang nyata, Yang Maha Perkasa lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/032006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:7', 32, 7, 21, 415, 3510, 'الَّذِيْٓ اَحْسَنَ كُلَّ شَيْءٍ خَلَقَهٗ وَبَدَاَ خَلْقَ الْاِنْسَانِ مِنْ طِيْنٍ', '(Dia juga) yang memperindah segala sesuatu yang Dia ciptakan dan memulai penciptaan manusia dari tanah.', '', 'https://everyayah.com/data/Alafasy_128kbps/032007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:8', 32, 8, 21, 415, 3511, 'ثُمَّ جَعَلَ نَسْلَهٗ مِنْ سُلٰلَةٍ مِّنْ مَّاۤءٍ مَّهِيْنٍ ۚ ', 'Kemudian, Dia menjadikan keturunannya dari sari pati air yang hina (air mani).', '', 'https://everyayah.com/data/Alafasy_128kbps/032008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:9', 32, 9, 21, 415, 3512, 'ثُمَّ سَوّٰىهُ وَنَفَخَ فِيْهِ مِنْ رُّوْحِهٖ وَجَعَلَ لَكُمُ السَّمْعَ وَالْاَبْصَارَ وَالْاَفْـِٕدَةَۗ قَلِيْلًا مَّا تَشْكُرُوْنَ ', 'Kemudian, Dia menyempurnakannya dan meniupkan roh (ciptaan)-Nya ke dalam (tubuh)-nya. Dia menjadikan pendengaran, penglihatan, dan hati nurani untukmu. Sedikit sekali kamu bersyukur.', '', 'https://everyayah.com/data/Alafasy_128kbps/032009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:10', 32, 10, 21, 415, 3513, 'وَقَالُوْٓا ءَاِذَا ضَلَلْنَا فِى الْاَرْضِ ءَاِنَّا لَفِيْ خَلْقٍ جَدِيْدٍ ەۗ بَلْ هُمْ بِلِقَاۤءِ رَبِّهِمْ كٰفِرُوْنَ ', 'Mereka berkata, “Apakah apabila kami telah lenyap (hancur) di dalam tanah, kami akan (kembali) dalam ciptaan yang baru?”606) Bahkan (bukan hanya itu), mereka pun mengingkari pertemuan dengan Tuhannya.', '606) Mereka dihidupkan kembali untuk menerima balasan Allah Swt. pada hari Kiamat.', 'https://everyayah.com/data/Alafasy_128kbps/032010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:11', 32, 11, 21, 415, 3514, '۞ قُلْ يَتَوَفّٰىكُمْ مَّلَكُ الْمَوْتِ الَّذِيْ وُكِّلَ بِكُمْ ثُمَّ اِلٰى رَبِّكُمْ تُرْجَعُوْنَ ࣖ ', 'Katakanlah, “Malaikat maut yang diserahi (tugas) untuk (mencabut nyawa)-mu akan mematikanmu, kemudian kepada Tuhanmulah kamu akan dikembalikan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/032011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:12', 32, 12, 21, 416, 3515, 'وَلَوْ تَرٰىٓ اِذِ الْمُجْرِمُوْنَ نَاكِسُوْا رُءُوْسِهِمْ عِنْدَ رَبِّهِمْۗ رَبَّنَآ اَبْصَرْنَا وَسَمِعْنَا فَارْجِعْنَا نَعْمَلْ صَالِحًا اِنَّا مُوْقِنُوْنَ ', 'Sekiranya kamu melihat orang-orang yang berdosa itu menundukkan kepalanya di hadapan Tuhannya, (kamu akan melihat sesuatu yang sangat luar biasa dan mereka berkata,) “Ya Tuhan kami, kami telah melihat (hari Kiamat yang kami ingkari) dan mendengar (dari-Mu kebenaran ucapan rasul-rasul-Mu). Maka, kembalikanlah kami (ke dunia), niscaya kami akan beramal saleh. Sesungguhnya kami (sekarang) adalah orang-orang yang yakin (akan adanya hari Kiamat).”', '', 'https://everyayah.com/data/Alafasy_128kbps/032012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:13', 32, 13, 21, 416, 3516, 'وَلَوْ شِئْنَا لَاٰتَيْنَا كُلَّ نَفْسٍ هُدٰىهَا وَلٰكِنْ حَقَّ الْقَوْلُ مِنِّيْ لَاَمْلَـَٔنَّ جَهَنَّمَ مِنَ الْجِنَّةِ وَالنَّاسِ اَجْمَعِيْنَ ', 'Seandainya Kami menghendaki, niscaya Kami menganugerahkan kepada setiap jiwa petunjuk (bagi)-nya, tetapi telah berlaku ketetapan dari-Ku (bahwa) sungguh Aku pasti akan memenuhi (neraka) Jahanam dengan jin dan manusia bersama-sama.', '', 'https://everyayah.com/data/Alafasy_128kbps/032013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:14', 32, 14, 21, 416, 3517, 'فَذُوْقُوْا بِمَا نَسِيْتُمْ لِقَاۤءَ يَوْمِكُمْ هٰذَاۚ اِنَّا نَسِيْنٰكُمْ وَذُوْقُوْا عَذَابَ الْخُلْدِ بِمَا كُنْتُمْ تَعْمَلُوْنَ', 'Rasakanlah olehmu (azab ini) karena kamu melalaikan pertemuan dengan harimu ini (hari Kiamat). Sesungguhnya Kami pun melalaikanmu. Rasakanlah azab yang kekal karena apa yang selalu kamu kerjakan!”', '', 'https://everyayah.com/data/Alafasy_128kbps/032014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:15', 32, 15, 21, 416, 3518, 'اِنَّمَا يُؤْمِنُ بِاٰيٰتِنَا الَّذِيْنَ اِذَا ذُكِّرُوْا بِهَا خَرُّوْا سُجَّدًا وَّسَبَّحُوْا بِحَمْدِ رَبِّهِمْ وَهُمْ لَا يَسْتَكْبِرُوْنَ ۩ ', 'Sesungguhnya orang-orang yang beriman dengan ayat-ayat Kami, hanyalah orang-orang yang apabila diperingatkan dengannya (ayat-ayat Kami), mereka menyungkur (dalam keadaan) sujud dan bertasbih serta memuji Tuhannya dan mereka pun tidak menyombongkan diri.', '', 'https://everyayah.com/data/Alafasy_128kbps/032015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:16', 32, 16, 21, 416, 3519, 'تَتَجَافٰى جُنُوْبُهُمْ عَنِ الْمَضَاجِعِ يَدْعُوْنَ رَبَّهُمْ خَوْفًا وَّطَمَعًاۖ وَّمِمَّا رَزَقْنٰهُمْ يُنْفِقُوْنَ', 'Lambung (tubuh) mereka jauh dari tempat tidur (untuk salat malam) seraya berdoa kepada Tuhannya dengan rasa takut (akan siksa-Nya) dan penuh harap (akan rahmat-Nya) dan mereka menginfakkan sebagian dari rezeki yang Kami anugerahkan kepada mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/032016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:17', 32, 17, 21, 416, 3520, 'فَلَا تَعْلَمُ نَفْسٌ مَّآ اُخْفِيَ لَهُمْ مِّنْ قُرَّةِ اَعْيُنٍۚ جَزَاۤءًۢ بِمَا كَانُوْا يَعْمَلُوْنَ', 'Tidak seorang pun mengetahui apa yang disembunyikan untuk mereka berupa (macam-macam nikmat) yang menyenangkan hati sebagai balasan terhadap apa yang selalu mereka kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/032017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:18', 32, 18, 21, 416, 3521, 'اَفَمَنْ كَانَ مُؤْمِنًا كَمَنْ كَانَ فَاسِقًاۗ  لَا يَسْتَوٗنَ', 'Apakah orang mukmin sama dengan orang fasik (kafir)? (Pastilah) mereka tidak sama.', '', 'https://everyayah.com/data/Alafasy_128kbps/032018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:19', 32, 19, 21, 416, 3522, 'اَمَّا الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ فَلَهُمْ جَنّٰتُ الْمَأْوٰىۖ  نُزُلًا ۢبِمَا كَانُوْا يَعْمَلُوْنَ', 'Adapun orang-orang yang beriman dan mengerjakan amal saleh, mereka akan mendapat surga-surga (sebagai) tempat kediaman sebagai balasan atas apa yang selalu mereka kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/032019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:20', 32, 20, 21, 416, 3523, 'وَاَمَّا الَّذِيْنَ فَسَقُوْا فَمَأْوٰىهُمُ النَّارُ كُلَّمَآ اَرَادُوْٓا اَنْ يَّخْرُجُوْا مِنْهَآ اُعِيْدُوْا فِيْهَا وَقِيْلَ لَهُمْ ذُوْقُوْا عَذَابَ النَّارِ الَّذِيْ كُنْتُمْ بِهٖ تُكَذِّبُوْنَ', 'Adapun orang-orang yang fasik (kafir), tempat kediaman mereka adalah neraka. Setiap kali mereka hendak keluar darinya, mereka dikembalikan (lagi) ke dalamnya dan dikatakan kepada mereka, “Rasakanlah azab neraka yang dahulu selalu kamu dustakan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/032020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:21', 32, 21, 21, 417, 3524, 'وَلَنُذِيْقَنَّهُمْ مِّنَ الْعَذَابِ الْاَدْنٰى دُوْنَ الْعَذَابِ الْاَكْبَرِ لَعَلَّهُمْ يَرْجِعُوْنَ', 'Kami pasti akan menimpakan kepada mereka sebagian azab yang dekat (di dunia) sebelum azab yang lebih besar (di akhirat) agar mereka kembali (ke jalan yang benar).', '', 'https://everyayah.com/data/Alafasy_128kbps/032021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:22', 32, 22, 21, 417, 3525, 'وَمَنْ اَظْلَمُ مِمَّنْ ذُكِّرَ بِاٰيٰتِ رَبِّهٖ ثُمَّ اَعْرَضَ عَنْهَا ۗاِنَّا مِنَ الْمُجْرِمِيْنَ مُنْتَقِمُوْنَ ࣖ', 'Siapakah yang lebih zalim daripada orang yang telah diperingatkan dengan ayat-ayat Tuhannya, kemudian dia berpaling darinya? Sesungguhnya Kami akan memberikan balasan kepada para pendosa.', '', 'https://everyayah.com/data/Alafasy_128kbps/032022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:23', 32, 23, 21, 417, 3526, 'وَلَقَدْ اٰتَيْنَا مُوْسَى الْكِتٰبَ فَلَا تَكُنْ فِيْ مِرْيَةٍ مِّنْ لِّقَاۤىِٕهٖ وَجَعَلْنٰهُ هُدًى لِّبَنِيْٓ اِسْرَاۤءِيْلَۚ', 'Sungguh, Kami benar-benar telah menganugerahkan Kitab (Taurat) kepada Musa. Maka, janganlah engkau (Nabi Muhammad) ragu-ragu menerimanya (Al-Qur’an) dan Kami menjadikan Kitab (Taurat) itu sebagai petunjuk bagi Bani Israil.', '', 'https://everyayah.com/data/Alafasy_128kbps/032023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:24', 32, 24, 21, 417, 3527, 'وَجَعَلْنَا مِنْهُمْ اَىِٕمَّةً يَّهْدُوْنَ بِاَمْرِنَا لَمَّا صَبَرُوْاۗ وَكَانُوْا بِاٰيٰتِنَا يُوْقِنُوْنَ', 'Kami menjadikan di antara mereka itu pemimpin-pemimpin yang memberi petunjuk dengan perintah Kami selama mereka bersabar. Mereka selalu meyakini ayat-ayat Kami.', '', 'https://everyayah.com/data/Alafasy_128kbps/032024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:25', 32, 25, 21, 417, 3528, 'اِنَّ رَبَّكَ هُوَ يَفْصِلُ بَيْنَهُمْ يَوْمَ الْقِيٰمَةِ فِيْمَا كَانُوْا فِيْهِ يَخْتَلِفُوْنَ', 'Sesungguhnya Tuhanmu, Dialah yang memutuskan di antara mereka pada hari Kiamat apa yang dahulu selalu mereka perselisihkan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/032025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:26', 32, 26, 21, 417, 3529, 'اَوَلَمْ يَهْدِ لَهُمْ كَمْ اَهْلَكْنَا مِنْ قَبْلِهِمْ مِّنَ الْقُرُوْنِ يَمْشُوْنَ فِيْ مَسٰكِنِهِمْ ۗاِنَّ فِيْ ذٰلِكَ لَاٰيٰتٍۗ اَفَلَا يَسْمَعُوْنَ', 'Tidakkah menjadi petunjuk bagi mereka (kaum kafir Makkah), betapa banyak umat sebelum mereka yang telah Kami binasakan, sedangkan mereka sendiri berjalan di tempat-tempat kediaman mereka itu. Sesungguhnya pada yang demikian itu terdapat tanda-tanda (kekuasaan Allah). Apakah mereka tidak mendengarkan (memperhatikan)?', '', 'https://everyayah.com/data/Alafasy_128kbps/032026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:27', 32, 27, 21, 417, 3530, 'اَوَلَمْ يَرَوْا اَنَّا نَسُوْقُ الْمَاۤءَ اِلَى الْاَرْضِ الْجُرُزِ فَنُخْرِجُ بِهٖ زَرْعًا تَأْكُلُ مِنْهُ اَنْعَامُهُمْ وَاَنْفُسُهُمْۗ اَفَلَا يُبْصِرُوْنَ', 'Tidakkah mereka memperhatikan bahwa Kami mengarahkan (awan yang mengandung) air ke bumi yang tandus, lalu Kami menumbuhkan dengannya (air hujan) tanam-tanaman, sehingga hewan-hewan ternak mereka dan mereka sendiri dapat makan darinya. Maka, mengapa mereka tidak memperhatikan?', '', 'https://everyayah.com/data/Alafasy_128kbps/032027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:28', 32, 28, 21, 417, 3531, 'وَيَقُوْلُوْنَ مَتٰى هٰذَا الْفَتْحُ اِنْ كُنْتُمْ صٰدِقِيْنَ', 'Mereka bertanya, “Kapankah kemenangan itu (datang) jika engkau orang yang benar?”', '', 'https://everyayah.com/data/Alafasy_128kbps/032028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:29', 32, 29, 21, 417, 3532, 'قُلْ يَوْمَ الْفَتْحِ لَا يَنْفَعُ الَّذِيْنَ كَفَرُوْٓا اِيْمَانُهُمْ وَلَا هُمْ يُنْظَرُوْنَ', 'Katakanlah, “Pada hari kemenangan itu tidak berguna lagi bagi orang-orang kafir keimanan mereka dan mereka tidak diberi penangguhan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/032029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('32:30', 32, 30, 21, 417, 3533, 'فَاَعْرِضْ عَنْهُمْ وَانْتَظِرْ اِنَّهُمْ مُّنْتَظِرُوْنَ ࣖ', 'Maka, berpalinglah dari mereka dan tunggulah! Sesungguhnya mereka (juga) menunggu.', '', 'https://everyayah.com/data/Alafasy_128kbps/032030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:1', 33, 1, 21, 418, 3534, 'يٰٓاَيُّهَا النَّبِيُّ اتَّقِ اللّٰهَ وَلَا تُطِعِ الْكٰفِرِيْنَ وَالْمُنٰفِقِيْنَ ۗاِنَّ اللّٰهَ كَانَ عَلِيْمًا حَكِيْمًاۙ ', 'Wahai Nabi, bertakwalah kepada Allah dan janganlah engkau menuruti (keinginan) orang-orang kafir dan orang-orang munafik. Sesungguhnya Allah Maha Mengetahui lagi Maha Bijaksana.', '', 'https://everyayah.com/data/Alafasy_128kbps/033001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:2', 33, 2, 21, 418, 3535, 'وَّاتَّبِعْ مَا يُوْحٰىٓ اِلَيْكَ مِنْ رَّبِّكَ ۗاِنَّ اللّٰهَ كَانَ بِمَا تَعْمَلُوْنَ خَبِيْرًاۙ ', 'Ikutilah apa yang diwahyukan Tuhanmu kepadamu. Sesungguhnya Allah Maha Teliti terhadap apa yang kamu kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/033002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:3', 33, 3, 21, 418, 3536, 'وَّتَوَكَّلْ عَلَى اللّٰهِ ۗوَكَفٰى بِاللّٰهِ وَكِيْلًا', 'Bertawakallah kepada Allah. Cukuplah Allah sebagai pemelihara.', '', 'https://everyayah.com/data/Alafasy_128kbps/033003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:4', 33, 4, 21, 418, 3537, 'مَا جَعَلَ اللّٰهُ لِرَجُلٍ مِّنْ قَلْبَيْنِ فِيْ جَوْفِهٖ ۚوَمَا جَعَلَ اَزْوَاجَكُمُ الّٰـِٕۤيْ تُظٰهِرُوْنَ مِنْهُنَّ اُمَّهٰتِكُمْ ۚوَمَا جَعَلَ اَدْعِيَاۤءَكُمْ اَبْنَاۤءَكُمْۗ ذٰلِكُمْ قَوْلُكُمْ بِاَفْوَاهِكُمْ ۗوَاللّٰهُ يَقُوْلُ الْحَقَّ وَهُوَ يَهْدِى السَّبِيْلَ', 'Allah tidak menjadikan bagi seseorang dua hati dalam rongganya, Dia tidak menjadikan istri-istrimu yang kamu zihar itu sebagai ibumu, dan Dia pun tidak menjadikan anak angkatmu sebagai anak kandungmu (sendiri). Yang demikian itu hanyalah perkataan di mulutmu saja. Allah mengatakan sesuatu yang hak dan Dia menunjukkan jalan (yang benar).', '', 'https://everyayah.com/data/Alafasy_128kbps/033004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:5', 33, 5, 21, 418, 3538, 'اُدْعُوْهُمْ لِاٰبَاۤىِٕهِمْ هُوَ اَقْسَطُ عِنْدَ اللّٰهِ ۚ فَاِنْ لَّمْ تَعْلَمُوْٓا اٰبَاۤءَهُمْ فَاِخْوَانُكُمْ فِى الدِّيْنِ وَمَوَالِيْكُمْ ۗوَلَيْسَ عَلَيْكُمْ جُنَاحٌ فِيْمَآ اَخْطَأْتُمْ بِهٖ وَلٰكِنْ مَّا تَعَمَّدَتْ قُلُوْبُكُمْ ۗوَكَانَ اللّٰهُ غَفُوْرًا رَّحِيْمًا', 'Panggillah mereka (anak angkat itu) dengan (memakai) nama bapak mereka. Itulah yang adil di sisi Allah. Jika kamu tidak mengetahui bapak mereka, (panggillah mereka sebagai) saudara-saudaramu seagama dan maula-maulamu.607) Tidak ada dosa atasmu jika kamu khilaf tentang itu, tetapi (yang ada dosanya) apa yang disengaja oleh hatimu. Allah Maha Pengampun lagi Maha Penyayang.', '607) Yang dimaksud dengan maula dalam ayat ini adalah teman dekat.', 'https://everyayah.com/data/Alafasy_128kbps/033005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:6', 33, 6, 21, 418, 3539, 'اَلنَّبِيُّ اَوْلٰى بِالْمُؤْمِنِيْنَ مِنْ اَنْفُسِهِمْ وَاَزْوَاجُهٗٓ اُمَّهٰتُهُمْ ۗوَاُولُوا الْاَرْحَامِ بَعْضُهُمْ اَوْلٰى بِبَعْضٍ فِيْ كِتٰبِ اللّٰهِ مِنَ الْمُؤْمِنِيْنَ وَالْمُهٰجِرِيْنَ اِلَّآ اَنْ تَفْعَلُوْٓا اِلٰٓى اَوْلِيَاۤىِٕكُمْ مَّعْرُوْفًا ۗ كَانَ ذٰلِكَ فِى الْكِتٰبِ مَسْطُوْرًا', 'Nabi itu lebih utama bagi orang-orang mukmin dibandingkan diri mereka sendiri dan istri-istrinya adalah ibu-ibu mereka. Orang-orang yang mempunyai hubungan darah satu sama lain lebih berhak (saling mewarisi) di dalam Kitab Allah daripada orang-orang mukmin dan orang-orang Muhajirin, kecuali kalau kamu hendak berbuat baik kepada saudara-saudaramu (seagama). Demikian itu telah tertulis dalam Kitab (Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/033006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:7', 33, 7, 21, 419, 3540, 'وَاِذْ اَخَذْنَا مِنَ النَّبِيّٖنَ مِيْثَاقَهُمْ وَمِنْكَ وَمِنْ نُّوْحٍ وَّاِبْرٰهِيْمَ وَمُوْسٰى وَعِيْسَى ابْنِ مَرْيَمَ ۖوَاَخَذْنَا مِنْهُمْ مِّيْثَاقًا غَلِيْظًاۙ', '(Ingatlah) ketika Kami mengambil perjanjian dari para nabi, darimu (Nabi Muhammad), dari Nuh, Ibrahim, Musa, dan Isa putra Maryam. Kami telah mengambil dari mereka perjanjian yang teguh,608)', '608) Yang dimaksud dengan perjanjian teguh yang diambil dari para nabi adalah kesanggupan mereka untuk menyampaikan agama kepada umatnya masing-masing.', 'https://everyayah.com/data/Alafasy_128kbps/033007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:8', 33, 8, 21, 419, 3541, 'لِّيَسْـَٔلَ الصّٰدِقِيْنَ عَنْ صِدْقِهِمْ ۚوَاَعَدَّ لِلْكٰفِرِيْنَ عَذَابًا اَلِيْمًا ࣖ', 'agar Dia menanyakan kepada orang-orang yang benar tentang kebenaran mereka.609) Dia menyediakan azab yang pedih bagi orang-orang kafir.', '609) Pada hari Kiamat Allah Swt. akan menanyakan kepada para rasul sampai di mana usaha mereka menyampaikan ajaran Allah Swt. kepada umatnya dan sampai di mana umatnya melaksanakan ajaran Allah Swt. itu.', 'https://everyayah.com/data/Alafasy_128kbps/033008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:9', 33, 9, 21, 419, 3542, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوا اذْكُرُوْا نِعْمَةَ اللّٰهِ عَلَيْكُمْ اِذْ جَاۤءَتْكُمْ جُنُوْدٌ فَاَرْسَلْنَا عَلَيْهِمْ رِيْحًا وَّجُنُوْدًا لَّمْ تَرَوْهَا ۗوَكَانَ اللّٰهُ بِمَا تَعْمَلُوْنَ بَصِيْرًاۚ ', 'Wahai orang-orang yang beriman, ingatlah nikmat Allah (yang telah dikaruniakan) kepadamu ketika bala tentara datang kepadamu, lalu Kami kirimkan kepada mereka angin topan dan bala tentara (malaikat) yang tidak dapat terlihat olehmu.610) Allah Maha Melihat apa yang kamu kerjakan.', '610) Ayat ini menerangkan kisah bala tentara kafir yang dikalahkan dalam Perang Khandaq (Ahzab).', 'https://everyayah.com/data/Alafasy_128kbps/033009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:10', 33, 10, 21, 419, 3543, 'اِذْ جَاۤءُوْكُمْ مِّنْ فَوْقِكُمْ وَمِنْ اَسْفَلَ مِنْكُمْ وَاِذْ زَاغَتِ الْاَبْصَارُ وَبَلَغَتِ الْقُلُوْبُ الْحَنَاجِرَ وَتَظُنُّوْنَ بِاللّٰهِ الظُّنُوْنَا۠   ۗ', 'Ketika mereka datang kepadamu dari arah atas dan bawahmu, ketika penglihatan(-mu) terpana, hatimu menyesak sampai ke tenggorokan,611) dan kamu berprasangka yang bukan-bukan terhadap Allah,', '611) Ayat ini menggambarkan begitu hebatnya perasaan takut dan gentar kaum mukmin pada waktu itu.', 'https://everyayah.com/data/Alafasy_128kbps/033010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:11', 33, 11, 21, 419, 3544, 'هُنَالِكَ ابْتُلِيَ الْمُؤْمِنُوْنَ وَزُلْزِلُوْا زِلْزَالًا شَدِيْدًا', 'di situlah orang-orang mukmin diuji dan diguncangkan (hatinya) dengan guncangan yang dahsyat.', '', 'https://everyayah.com/data/Alafasy_128kbps/033011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:12', 33, 12, 21, 419, 3545, 'وَاِذْ يَقُوْلُ الْمُنٰفِقُوْنَ وَالَّذِيْنَ فِيْ قُلُوْبِهِمْ مَّرَضٌ مَّا وَعَدَنَا اللّٰهُ وَرَسُوْلُهٗٓ اِلَّا غُرُوْرًا', '(Ingatlah) ketika orang-orang munafik dan orang-orang yang di hatinya terdapat penyakit berkata, “Apa yang dijanjikan Allah dan Rasul-Nya kepada kami hanyalah tipu daya belaka.”', '', 'https://everyayah.com/data/Alafasy_128kbps/033012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:13', 33, 13, 21, 419, 3546, 'وَاِذْ قَالَتْ طَّاۤىِٕفَةٌ مِّنْهُمْ يٰٓاَهْلَ يَثْرِبَ لَا مُقَامَ لَكُمْ فَارْجِعُوْا ۚوَيَسْتَأْذِنُ فَرِيْقٌ مِّنْهُمُ النَّبِيَّ يَقُوْلُوْنَ اِنَّ بُيُوْتَنَا عَوْرَةٌ  ۗوَمَا هِيَ بِعَوْرَةٍ ۗاِنْ يُّرِيْدُوْنَ اِلَّا فِرَارًا', '(Ingatlah) ketika segolongan di antara mereka berkata, “Wahai penduduk Yasrib (Madinah), tidak ada tempat bagimu. Maka, kembalilah kamu!” Sebagian dari mereka meminta izin kepada Nabi (untuk kembali pulang) dengan berkata, “Sesungguhnya rumah-rumah kami terbuka (tidak ada penjaga).” Padahal, rumah-rumah itu tidak terbuka. Mereka hanya ingin lari (dari peperangan).', '', 'https://everyayah.com/data/Alafasy_128kbps/033013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:14', 33, 14, 21, 419, 3547, 'وَلَوْ دُخِلَتْ عَلَيْهِمْ مِّنْ اَقْطَارِهَا ثُمَّ سُىِٕلُوا الْفِتْنَةَ لَاٰتَوْهَا وَمَا تَلَبَّثُوْا بِهَآ اِلَّا يَسِيْرًا', 'Seandainya (Yasrib) diserang dari segala penjuru, kemudian mereka diminta untuk melakukan fitnah,612) niscaya mereka mengerjakannya. Mereka tidak menunda permintaan itu, kecuali hanya sebentar.', '612) Fitnah yang dimaksud dalam ayat ini adalah melakukan kekacauan, seperti murtad dan membantu pasukan musuh dalam peperangan.', 'https://everyayah.com/data/Alafasy_128kbps/033014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:15', 33, 15, 21, 419, 3548, 'وَلَقَدْ كَانُوْا عَاهَدُوا اللّٰهَ مِنْ قَبْلُ لَا يُوَلُّوْنَ الْاَدْبَارَ ۗوَكَانَ عَهْدُ اللّٰهِ مَسْـُٔوْلًا', 'Sungguh, mereka sebelum itu benar-benar telah berjanji kepada Allah tidak akan berbalik ke belakang (mundur). Perjanjian dengan Allah akan diminta pertanggungjawabannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/033015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:16', 33, 16, 21, 420, 3549, 'قُلْ لَّنْ يَّنْفَعَكُمُ الْفِرَارُ اِنْ فَرَرْتُمْ مِّنَ الْمَوْتِ اَوِ الْقَتْلِ وَاِذًا لَّا تُمَتَّعُوْنَ اِلَّا قَلِيْلًا ', 'Katakanlah (Nabi Muhammad), “Lari itu tidak akan berguna bagimu ketika kamu lari dari kematian atau pembunuhan. Jika demikian, kamu tidak akan mengecap kesenangan, kecuali sebentar saja.”', '', 'https://everyayah.com/data/Alafasy_128kbps/033016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:17', 33, 17, 21, 420, 3550, 'قُلْ مَنْ ذَا الَّذِيْ يَعْصِمُكُمْ مِّنَ اللّٰهِ اِنْ اَرَادَ بِكُمْ سُوْۤءًا اَوْ اَرَادَ بِكُمْ رَحْمَةً ۗوَلَا يَجِدُوْنَ لَهُمْ مِّنْ دُوْنِ اللّٰهِ وَلِيًّا وَّلَا نَصِيْرًا', 'Katakanlah, “Siapa yang dapat melindungi kamu dari (ketentuan) Allah jika Dia menghendaki bencana atasmu atau menghendaki rahmat untuk dirimu?” Mereka itu tidak akan mendapatkan pelindung dan penolong selain Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/033017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:18', 33, 18, 21, 420, 3551, '۞ قَدْ يَعْلَمُ اللّٰهُ الْمُعَوِّقِيْنَ مِنْكُمْ وَالْقَاۤىِٕلِيْنَ لِاِخْوَانِهِمْ هَلُمَّ اِلَيْنَا ۚوَلَا يَأْتُوْنَ الْبَأْسَ اِلَّا قَلِيْلًاۙ', 'Sungguh, Allah mengetahui para penghalang (untuk berperang) dari (golongan)-mu dan orang yang berkata kepada saudara-saudaranya, “Marilah bersama kami.” Mereka tidak datang berperang, kecuali hanya sebentar.', '', 'https://everyayah.com/data/Alafasy_128kbps/033018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:19', 33, 19, 21, 420, 3552, 'اَشِحَّةً عَلَيْكُمْ ۖ فَاِذَا جَاۤءَ الْخَوْفُ رَاَيْتَهُمْ يَنْظُرُوْنَ اِلَيْكَ تَدُوْرُ اَعْيُنُهُمْ كَالَّذِيْ يُغْشٰى عَلَيْهِ مِنَ الْمَوْتِۚ فَاِذَا ذَهَبَ الْخَوْفُ سَلَقُوْكُمْ بِاَلْسِنَةٍ حِدَادٍ اَشِحَّةً عَلَى الْخَيْرِۗ اُولٰۤىِٕكَ لَمْ يُؤْمِنُوْا فَاَحْبَطَ اللّٰهُ اَعْمَالَهُمْۗ وَكَانَ ذٰلِكَ عَلَى اللّٰهِ يَسِيْرًا', 'Mereka (kaum munafik) kikir terhadapmu. Apabila datang ketakutan (bahaya), kamu melihat mereka memandang kepadamu dengan bola mata yang berputar-putar seperti orang yang pingsan karena akan mati. Apabila ketakutan telah hilang, mereka mencacimu dengan lidah yang tajam, sementara mereka kikir untuk berbuat kebaikan. Mereka itu tidak beriman, maka Allah menghapus amalnya. Hal yang demikian itu sangat mudah bagi Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/033019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:20', 33, 20, 21, 420, 3553, 'يَحْسَبُوْنَ الْاَحْزَابَ لَمْ يَذْهَبُوْا ۚوَاِنْ يَّأْتِ الْاَحْزَابُ يَوَدُّوْا لَوْ اَنَّهُمْ بَادُوْنَ فِى الْاَعْرَابِ يَسْاَلُوْنَ عَنْ اَنْۢبَاۤىِٕكُمْ ۗوَلَوْ كَانُوْا فِيْكُمْ مَّا قٰتَلُوْٓا اِلَّا قَلِيْلًا ࣖ', 'Mereka mengira (bahwa) golongan-golongan (yang bersekutu) itu belum pergi. Jika golongan-golongan itu datang kembali, mereka pasti ingin berada di dusun-dusun bersama-sama orang Arab Badui, sambil menanyakan berita tentangmu. Seandainya mereka berada bersamamu, niscaya mereka tidak akan berperang, kecuali sebentar saja.', '', 'https://everyayah.com/data/Alafasy_128kbps/033020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:21', 33, 21, 21, 420, 3554, 'لَقَدْ كَانَ لَكُمْ فِيْ رَسُوْلِ اللّٰهِ اُسْوَةٌ حَسَنَةٌ لِّمَنْ كَانَ يَرْجُوا اللّٰهَ وَالْيَوْمَ الْاٰخِرَ وَذَكَرَ اللّٰهَ كَثِيْرًاۗ', 'Sungguh, pada (diri) Rasulullah benar-benar ada suri teladan yang baik bagimu, (yaitu) bagi orang yang mengharap (rahmat) Allah dan (kedatangan) hari Kiamat serta yang banyak mengingat Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/033021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:22', 33, 22, 21, 420, 3555, 'وَلَمَّا رَاَ الْمُؤْمِنُوْنَ الْاَحْزَابَۙ قَالُوْا هٰذَا مَا وَعَدَنَا اللّٰهُ وَرَسُوْلُهٗ وَصَدَقَ اللّٰهُ وَرَسُوْلُهٗ  ۖوَمَا زَادَهُمْ اِلَّآ اِيْمَانًا وَّتَسْلِيْمًاۗ ', 'Ketika orang-orang mukmin melihat golongan-golongan (yang bersekutu) itu, mereka berkata, “Inilah yang dijanjikan Allah dan Rasul-Nya613) kepada kita.” Benarlah Allah dan Rasul-Nya. Hal itu justru makin menambah keimanan dan keislaman mereka.', '613) Yang dijanjikan Allah Swt. dan Rasul itu adalah kemenangan setelah mengalami kesukaran.', 'https://everyayah.com/data/Alafasy_128kbps/033022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:23', 33, 23, 21, 421, 3556, 'مِنَ الْمُؤْمِنِيْنَ رِجَالٌ صَدَقُوْا مَا عَاهَدُوا اللّٰهَ عَلَيْهِ ۚ فَمِنْهُمْ مَّنْ قَضٰى نَحْبَهٗۙ وَمِنْهُمْ مَّنْ يَّنْتَظِرُ ۖوَمَا بَدَّلُوْا تَبْدِيْلًاۙ ', 'Di antara orang-orang mukmin itu ada orang-orang yang menepati apa yang telah mereka janjikan kepada Allah. Di antara mereka ada yang gugur dan di antara mereka ada (pula) yang menunggu-nunggu.614) Mereka sedikit pun tidak mengubah (janjinya)', '614) Yang dimaksud dengan menunggu pada ayat ini adalah menunggu salah satu di antara dua kebaikan, yakni menang atau mati syahid.', 'https://everyayah.com/data/Alafasy_128kbps/033023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:24', 33, 24, 21, 421, 3557, 'لِّيَجْزِيَ اللّٰهُ الصّٰدِقِيْنَ بِصِدْقِهِمْ وَيُعَذِّبَ الْمُنٰفِقِيْنَ اِنْ شَاۤءَ اَوْ يَتُوْبَ عَلَيْهِمْ ۗاِنَّ اللّٰهَ كَانَ غَفُوْرًا رَّحِيْمًاۚ ', 'agar Allah memberikan balasan kepada orang-orang yang benar itu karena kebenarannya dan mengazab orang munafik jika Dia menghendaki atau menerima tobat mereka. Sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/033024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:25', 33, 25, 21, 421, 3558, 'وَرَدَّ اللّٰهُ الَّذِيْنَ كَفَرُوْا بِغَيْظِهِمْ لَمْ يَنَالُوْا خَيْرًا ۗوَكَفَى اللّٰهُ الْمُؤْمِنِيْنَ الْقِتَالَ ۗوَكَانَ اللّٰهُ قَوِيًّا عَزِيْزًاۚ ', 'Allah menghalau orang-orang kafir itu dalam keadaan hati mereka penuh kejengkelan. Mereka tidak memperoleh keuntungan apa pun. Cukuplah Allah (yang menghindarkan) orang-orang mukmin dari peperangan.615) Allah Maha Kuat lagi Maha Perkasa.', '615) Dalam perang Khandaq, orang mukmin urung berperang sebab Allah Swt. telah menghalau musuh mereka dengan mengirimkan angin dan malaikat.', 'https://everyayah.com/data/Alafasy_128kbps/033025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:26', 33, 26, 21, 421, 3559, 'وَاَنْزَلَ الَّذِيْنَ ظَاهَرُوْهُمْ مِّنْ اَهْلِ الْكِتٰبِ مِنْ صَيَاصِيْهِمْ وَقَذَفَ فِيْ قُلُوْبِهِمُ الرُّعْبَ فَرِيْقًا تَقْتُلُوْنَ وَتَأْسِرُوْنَ فَرِيْقًاۚ ', 'Dia menurunkan orang-orang Ahlulkitab (Bani Quraizah) yang membantu mereka (golongan-golongan yang bersekutu) dari benteng-benteng mereka. Dia memasukkan rasa takut ke dalam hati mereka. Sebagian mereka kamu bunuh dan sebagian yang lain kamu tawan.616)', '616) Setelah golongan-golongan yang bersekutu itu kocar-kacir, Allah Swt. memerintahkan Nabi Muhammad saw. untuk menghukum Yahudi Bani Quraizah dan mengusir mereka dari benteng-benteng mereka. Seluruh laki-laki dewasa yang ikut berperang kemudian dibunuh, sedangkan perempuan dan anak-anak ditawan.', 'https://everyayah.com/data/Alafasy_128kbps/033026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:27', 33, 27, 21, 421, 3560, 'وَاَوْرَثَكُمْ اَرْضَهُمْ وَدِيَارَهُمْ وَاَمْوَالَهُمْ وَاَرْضًا لَّمْ تَطَـُٔوْهَا ۗوَكَانَ اللّٰهُ عَلٰى كُلِّ شَيْءٍ قَدِيْرًا ࣖ ', 'Dia mewariskan kepadamu tanah-tanah, rumah-rumah, harta benda mereka, dan tanah yang belum kamu injak.617) Allah Maha Kuasa terhadap segala sesuatu.', '617) Yang dimaksud tanah yang belum diinjak pada ayat ini adalah tanah yang akan dimasuki oleh tentara muslim.', 'https://everyayah.com/data/Alafasy_128kbps/033027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:28', 33, 28, 21, 421, 3561, 'يٰٓاَيُّهَا النَّبِيُّ قُلْ لِّاَزْوَاجِكَ اِنْ كُنْتُنَّ تُرِدْنَ الْحَيٰوةَ الدُّنْيَا وَزِيْنَتَهَا فَتَعَالَيْنَ اُمَتِّعْكُنَّ وَاُسَرِّحْكُنَّ سَرَاحًا جَمِيْلًا ', 'Wahai Nabi, katakanlah kepada istri-istrimu, “Jika kamu menginginkan kehidupan di dunia dan perhiasannya, kemarilah untuk kuberikan kepadamu mut‘ah dan aku ceraikan kamu dengan cara yang baik.', '', 'https://everyayah.com/data/Alafasy_128kbps/033028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:29', 33, 29, 21, 421, 3562, 'وَاِنْ كُنْتُنَّ تُرِدْنَ اللّٰهَ وَرَسُوْلَهٗ وَالدَّارَ الْاٰخِرَةَ فَاِنَّ اللّٰهَ اَعَدَّ لِلْمُحْسِنٰتِ مِنْكُنَّ اَجْرًا عَظِيْمًا', 'Jika kamu menginginkan Allah, Rasul-Nya, dan negeri akhirat, sesungguhnya Allah menyediakan pahala yang besar bagi siapa yang berbuat baik di antara kamu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/033029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:30', 33, 30, 21, 421, 3563, 'يٰنِسَاۤءَ النَّبِيِّ مَنْ يَّأْتِ مِنْكُنَّ بِفَاحِشَةٍ مُّبَيِّنَةٍ يُّضٰعَفْ لَهَا الْعَذَابُ ضِعْفَيْنِۗ وَكَانَ ذٰلِكَ عَلَى اللّٰهِ يَسِيْرًا   ۔', 'Wahai istri-istri Nabi, siapa di antara kamu yang melakukan perbuatan keji yang nyata, pasti azabnya akan dilipatgandakan dua kali lipat kepadanya. Hal yang demikian itu sangat mudah bagi Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/033030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:31', 33, 31, 22, 422, 3564, '۞ وَمَنْ يَّقْنُتْ مِنْكُنَّ لِلّٰهِ وَرَسُوْلِهٖ وَتَعْمَلْ صَالِحًا نُّؤْتِهَآ اَجْرَهَا مَرَّتَيْنِۙ وَاَعْتَدْنَا لَهَا رِزْقًا كَرِيْمًا ', 'Siapa di antara kamu (istri-istri Nabi) yang tetap taat kepada Allah dan Rasul-Nya dan mengerjakan amal saleh, niscaya Kami anugerahkan kepadanya pahala dua kali lipat dan Kami sediakan baginya rezeki yang mulia.', '', 'https://everyayah.com/data/Alafasy_128kbps/033031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:32', 33, 32, 22, 422, 3565, 'يٰنِسَاۤءَ النَّبِيِّ لَسْتُنَّ كَاَحَدٍ مِّنَ النِّسَاۤءِ اِنِ اتَّقَيْتُنَّ فَلَا تَخْضَعْنَ بِالْقَوْلِ فَيَطْمَعَ الَّذِيْ فِيْ قَلْبِهٖ مَرَضٌ وَّقُلْنَ قَوْلًا مَّعْرُوْفًاۚ ', 'Wahai istri-istri Nabi, kamu tidaklah seperti perempuan-perempuan yang lain jika kamu bertakwa. Maka, janganlah kamu merendahkan suara (dengan lemah lembut yang dibuat-buat) sehingga bangkit nafsu orang yang ada penyakit dalam hatinya dan ucapkanlah perkataan yang baik.', '', 'https://everyayah.com/data/Alafasy_128kbps/033032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:33', 33, 33, 22, 422, 3566, 'وَقَرْنَ فِيْ بُيُوْتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ الْجَاهِلِيَّةِ الْاُوْلٰى وَاَقِمْنَ الصَّلٰوةَ وَاٰتِيْنَ الزَّكٰوةَ وَاَطِعْنَ اللّٰهَ وَرَسُوْلَهٗ ۗاِنَّمَا يُرِيْدُ اللّٰهُ لِيُذْهِبَ عَنْكُمُ الرِّجْسَ اَهْلَ الْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيْرًاۚ ', 'Tetaplah (tinggal) di rumah-rumahmu dan janganlah berhias (dan bertingkah laku) seperti orang-orang jahiliah dahulu. Tegakkanlah salat, tunaikanlah zakat, serta taatilah Allah dan Rasul-Nya. Sesungguhnya Allah hanya hendak menghilangkan dosa darimu, wahai ahlulbait dan membersihkan kamu sebersih-bersihnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/033033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:34', 33, 34, 22, 422, 3567, 'وَاذْكُرْنَ مَا يُتْلٰى فِيْ بُيُوْتِكُنَّ مِنْ اٰيٰتِ اللّٰهِ وَالْحِكْمَةِۗ اِنَّ اللّٰهَ كَانَ لَطِيْفًا خَبِيْرًا ࣖ ', 'Ingatlah apa yang dibacakan di rumahmu yakni ayat-ayat Allah (Al-Qur’an) dan hikmah (sunah Nabimu). Sesungguhnya Allah Maha Lembut lagi Maha Teliti.', '', 'https://everyayah.com/data/Alafasy_128kbps/033034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:35', 33, 35, 22, 422, 3568, 'اِنَّ الْمُسْلِمِيْنَ وَالْمُسْلِمٰتِ وَالْمُؤْمِنِيْنَ وَالْمُؤْمِنٰتِ وَالْقٰنِتِيْنَ وَالْقٰنِتٰتِ وَالصّٰدِقِيْنَ وَالصّٰدِقٰتِ وَالصّٰبِرِيْنَ وَالصّٰبِرٰتِ وَالْخٰشِعِيْنَ وَالْخٰشِعٰتِ وَالْمُتَصَدِّقِيْنَ وَالْمُتَصَدِّقٰتِ وَالصَّاۤىِٕمِيْنَ وَالصّٰۤىِٕمٰتِ وَالْحٰفِظِيْنَ فُرُوْجَهُمْ وَالْحٰفِظٰتِ وَالذّٰكِرِيْنَ اللّٰهَ كَثِيْرًا وَّالذّٰكِرٰتِ اَعَدَّ اللّٰهُ لَهُمْ مَّغْفِرَةً وَّاَجْرًا عَظِيْمًا ', 'Sesungguhnya muslim dan muslimat, mukmin dan mukminat, laki-laki dan perempuan yang taat, laki-laki dan perempuan yang benar, laki-laki dan perempuan penyabar, laki-laki dan perempuan yang khusyuk, laki-laki dan perempuan yang bersedekah, laki-laki dan perempuan yang berpuasa, laki-laki dan perempuan yang memelihara kemaluannya, laki-laki dan perempuan yang banyak menyebut (nama) Allah, untuk mereka Allah telah menyiapkan ampunan dan pahala yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/033035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('33:36', 33, 36, 22, 423, 3569, 'وَمَا كَانَ لِمُؤْمِنٍ وَّلَا مُؤْمِنَةٍ اِذَا قَضَى اللّٰهُ وَرَسُوْلُهٗٓ اَمْرًا اَنْ يَّكُوْنَ لَهُمُ الْخِيَرَةُ مِنْ اَمْرِهِمْ ۗوَمَنْ يَّعْصِ اللّٰهَ وَرَسُوْلَهٗ فَقَدْ ضَلَّ ضَلٰلًا مُّبِيْنًاۗ  ', 'Tidaklah pantas bagi mukmin dan mukminat, apabila Allah dan Rasul-Nya telah menetapkan suatu ketentuan, akan ada pilihan (yang lain) bagi mereka tentang urusan mereka. Siapa yang mendurhakai Allah dan Rasul-Nya, sungguh dia telah tersesat dengan kesesatan yang nyata.', '', 'https://everyayah.com/data/Alafasy_128kbps/033036.mp3');
PRAGMA foreign_keys = ON;
